  // Check for select instructions with invariant conditions and constant operands
  // that may cause different cost modeling decisions
  for (auto *BB : TheLoop->blocks()) {
    for (auto &I : *BB) {
      if (auto *SI = dyn_cast<SelectInst>(&I)) {
        Value *Cond = SI->getCondition();
        Value *TrueVal = SI->getTrueValue();
        Value *FalseVal = SI->getFalseValue();

        // Check if condition is loop invariant
        if (!TheLoop->isLoopInvariant(Cond))
          continue;

        // Check if at least one operand is a constant
        if (isa<Constant>(TrueVal) || isa<Constant>(FalseVal)) {
          // Found a select with invariant condition and constant operand
          return true;
        }
